/* Umbral de snap en píxeles del preview */
const SNAP_THRESHOLD = 6;

const $ = (id) => document.getElementById(id);
function uid() { return 'el_' + (nextId++); }
function getStageRect() { return stage.getBoundingClientRect(); }
function stageW() { return stage.clientWidth; }
function stageH() { return stage.clientHeight; }

/* Precargar el logo como Image (del data URL base64) — reutilizable en export */
const LOGO_IMAGE = new Image();
LOGO_IMAGE.src = KROTON_LOGO_DATA_URL;
let LOGO_READY = false;
LOGO_IMAGE.onload = () => { LOGO_READY = true; };

/* ──────────── TABS ──────────── */
function switchTab(name, btn) {
  document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
  btn.classList.add('active');
  document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active'));
  $('tab-' + name).classList.add('active');
}

