let currentTemplate = 'fire';

function renderTemplates() {
  const grid = $('tplGrid');
  grid.innerHTML = TEMPLATES.map(t => `
    <div class="tpl-btn ${t.id === currentTemplate ? 'sel' : ''}" data-id="${t.id}" onclick="selectTemplate('${t.id}', this)">
      <div style="position:absolute;inset:0;overflow:hidden;">${t.render()}</div>
      <div class="tpl-name">${t.name}</div>
    </div>
  `).join('');
}

function selectTemplate(id, btn) {
  currentTemplate = id;
  document.querySelectorAll('.tpl-btn').forEach(b => b.classList.remove('sel'));
  if (btn) btn.classList.add('sel');
  const tpl = TEMPLATES.find(t => t.id === id);
  bgLayer.innerHTML = tpl.render();
}

/* ──────────── EMOJIS ──────────── */
function renderEmojis() {
  const tabsCt = $('emojiCatTabs');
  tabsCt.innerHTML = Object.keys(EMOJI_SETS).map(cat => `
    <div class="emoji-cat-tab ${cat === currentEmojiCat ? 'active' : ''}" onclick="switchEmojiCat('${cat}', this)">${EMOJI_CAT_ICONS[cat]}</div>
  `).join('');

  const grid = $('emojiGrid');
  grid.innerHTML = EMOJI_SETS[currentEmojiCat].map(e =>
    `<button class="emoji-btn" onclick="addEmoji('${e}')">${e}</button>`
  ).join('');
}

function switchEmojiCat(cat, btn) {
  currentEmojiCat = cat;
  document.querySelectorAll('.emoji-cat-tab').forEach(t => t.classList.remove('active'));
  if (btn) btn.classList.add('active');
  renderEmojis();
}

function addEmoji(char) {
  const id = uid();
  const dom = document.createElement('div');
  dom.className = 'el el-emoji';
  dom.dataset.id = id;
  dom.style.left = '40%';
  dom.style.top = '40%';
  dom.style.width = 'auto';
  dom.style.fontSize = '80px';
  dom.textContent = char;

  stage.appendChild(dom);
  const data = { id, type: 'emoji', dom, char, size: 80, rotation: 0 };
  elements.push(data);
  attachInteractions(data);
  selectElement(id);
  renderLayers();
}

/* ──────────── TEXT ──────────── */
function addText(content, preset) {
  const id = uid();
  const presets = {
    title: { size: 64, weight: '900', font: "'Bebas Neue', sans-serif", color: '#FCB827', align: 'center' },
    sub:   { size: 22, weight: '400', font: "'DM Sans', sans-serif", color: '#ffffff', align: 'center' },
    tip:   { size: 16, weight: '700', font: "'Space Mono', monospace", color: '#000000', align: 'center', bg: true }
  };
  const p = presets[preset] || presets.title;

  const dom = document.createElement('div');
  dom.className = 'el el-text';
  dom.dataset.id = id;
  dom.style.left = '10%';
  dom.style.top = '40%';
  dom.style.width = '80%';
  dom.style.fontSize = p.size + 'px';
  dom.style.fontWeight = p.weight;
  dom.style.fontFamily = p.font;
  dom.style.color = p.color;
  dom.style.textAlign = p.align;
  dom.textContent = content;
  if (p.bg) {
    dom.style.background = '#FCB827';
    dom.style.padding = '8px 16px';
    dom.style.borderRadius = '8px';
    dom.style.display = 'inline-block';
  }

  stage.appendChild(dom);
  const data = {
    id, type: 'text', dom,
    content, font: p.font, size: p.size,
    weight: p.weight, color: p.color, align: p.align,
    stroke: false, bg: !!p.bg, rotation: 0
  };
  elements.push(data);
  attachInteractions(data);
  selectElement(id);
  renderLayers();
}

/* ──────────── LOGO ──────────── */
function addLogo() {
  const id = uid();
  const dom = document.createElement('div');
  dom.className = 'el el-logo';
  dom.dataset.id = id;
  dom.style.left = '38%';
  dom.style.top = '38%';
  dom.style.width = '24%';
  dom.style.aspectRatio = '1/1';
  dom.style.backgroundImage = `url("${KROTON_LOGO_DATA_URL}")`;
  dom.style.backgroundColor = '#000';
  dom.style.borderRadius = '8px';
  stage.appendChild(dom);
  const data = { id, type: 'logo', dom, rotation: 0, opacity: 1 };
  elements.push(data);
  attachInteractions(data);
  selectElement(id);
  renderLayers();
  $('logoToggle').checked = true;
}

function toggleLogo() {
  const on = $('logoToggle').checked;
  const existing = elements.find(e => e.type === 'logo');
  if (on && !existing) {
    addLogo();
  } else if (!on && existing) {
    removeElement(existing.id);
  }
}

/* ══════════════════════════════════════════
   IMÁGENES SUBIDAS POR EL USUARIO
══════════════════════════════════════════ */
function handleFileUpload(files) {
  for (const file of files) {
    if (!file.type.startsWith('image/')) continue;
    if (file.size > 10 * 1024 * 1024) {
      showToast('⚠️ Imagen demasiado grande (máx 10MB)');
      continue;
    }
    const reader = new FileReader();
    reader.onload = (ev) => {
      const imgId = 'img_' + (nextImgId++);
      const dataUrl = ev.target.result;
      userImages.push({ id: imgId, dataUrl, name: file.name });
      renderMyImages();
      // Al subir, agrega automáticamente al canvas centrado
      addImageElement(dataUrl);
    };
    reader.readAsDataURL(file);
  }
}

function renderMyImages() {
  const grid = $('myImagesGrid');
  if (!userImages.length) {
    grid.innerHTML = '';
    return;
  }
  grid.innerHTML = userImages.map(img => `
    <div class="my-img-thumb" onclick="addImageElement('${escapeDataUrl(img.dataUrl)}')">
      <img src="${img.dataUrl}" alt="${escapeHtml(img.name)}">
      <button class="thumb-del" onclick="event.stopPropagation();deleteUserImage('${img.id}')">✕</button>
    </div>
  `).join('');
}

function escapeDataUrl(s) {
  // dataURLs son seguros, pero escapamos comillas por el onclick inline
  return s.replace(/'/g, "\\'");
}

function deleteUserImage(imgId) {
  userImages = userImages.filter(i => i.id !== imgId);
  renderMyImages();
}

function addImageElement(dataUrl) {
  const id = uid();
  const dom = document.createElement('div');
  dom.className = 'el el-image fit-contain';
  dom.dataset.id = id;
  dom.style.left = '25%';
  dom.style.top = '30%';
  dom.style.width = '50%';
  dom.style.aspectRatio = '1/1';
  dom.style.backgroundImage = `url("${dataUrl}")`;
  dom.style.borderRadius = '0px';

  // detectar aspect ratio real al cargar
  const probe = new Image();
  probe.onload = () => {
    const ar = probe.naturalWidth / probe.naturalHeight;
    dom.style.aspectRatio = ar.toFixed(4);
  };
  probe.src = dataUrl;

  stage.appendChild(dom);
  const data = {
    id, type: 'image', dom,
    dataUrl,
    fit: 'contain',
    opacity: 1,
    radius: 0,
    rotation: 0
  };
  elements.push(data);
  attachInteractions(data);
  selectElement(id);
  renderLayers();
}

/* Drag & drop directo en el área de upload */
function initUploadArea() {
  const area = $('uploadArea');
  const input = $('imgUpload');
  input.addEventListener('change', (e) => {
    handleFileUpload(e.target.files);
    input.value = '';
  });
  area.addEventListener('dragover', (e) => {
    e.preventDefault();
    area.classList.add('dragover');
  });
  area.addEventListener('dragleave', () => area.classList.remove('dragover'));
  area.addEventListener('drop', (e) => {
    e.preventDefault();
    area.classList.remove('dragover');
    handleFileUpload(e.dataTransfer.files);
  });
}

/* ──────────── INSTAGRAM LABEL ──────────── */
function addInstagramLabel(handle, textOnly) {
  const id = uid();
  const dom = document.createElement('div');
  dom.className = 'el el-iglabel';
  dom.dataset.id = id;
  dom.style.left = '25%';
  dom.style.top = '85%';

  const data = {
    id, type: 'iglabel', dom,
    text: handle, size: 16,
    showIcon: !textOnly, bg: true, rotation: 0
  };
  renderIgLabel(data);
  stage.appendChild(dom);
  elements.push(data);
  attachInteractions(data);
  selectElement(id);
  renderLayers();
}

function renderIgLabel(data) {
  const dom = data.dom;
  const iconSize = data.size * 1.5;
  const bgStyle = data.bg ? 'background:rgba(0,0,0,0.75);' : 'background:transparent;';
  const iconHtml = data.showIcon
    ? `<div class="igl-icon" style="width:${iconSize}px;height:${iconSize}px;">
        <svg viewBox="0 0 24 24" style="width:${iconSize * 0.6}px;height:${iconSize * 0.6}px;"><path d="M12 2.163c3.204 0 3.584.012 4.85.07 3.252.148 4.771 1.691 4.919 4.919.058 1.265.069 1.645.069 4.849 0 3.205-.012 3.584-.069 4.849-.149 3.225-1.664 4.771-4.919 4.919-1.266.058-1.644.07-4.85.07-3.204 0-3.584-.012-4.849-.07-3.26-.149-4.771-1.699-4.919-4.92-.058-1.265-.07-1.644-.07-4.849 0-3.204.013-3.583.07-4.849.149-3.227 1.664-4.771 4.919-4.919 1.266-.057 1.645-.069 4.849-.069zm0-2.163c-3.259 0-3.667.014-4.947.072-4.358.2-6.78 2.618-6.98 6.98-.059 1.281-.073 1.689-.073 4.948 0 3.259.014 3.668.072 4.948.2 4.358 2.618 6.78 6.98 6.98 1.281.058 1.689.072 4.948.072 3.259 0 3.668-.014 4.948-.072 4.354-.2 6.782-2.618 6.979-6.98.059-1.28.073-1.689.073-4.948 0-3.259-.014-3.667-.072-4.947-.196-4.354-2.617-6.78-6.979-6.98-1.281-.059-1.69-.073-4.949-.073zm0 5.838c-3.403 0-6.162 2.759-6.162 6.162s2.759 6.163 6.162 6.163 6.162-2.759 6.162-6.163c0-3.403-2.759-6.162-6.162-6.162zm0 10.162c-2.209 0-4-1.79-4-4 0-2.209 1.791-4 4-4s4 1.791 4 4c0 2.21-1.791 4-4 4zm6.406-11.845c-.796 0-1.441.645-1.441 1.44s.645 1.44 1.441 1.44c.795 0 1.439-.645 1.439-1.44s-.644-1.44-1.439-1.44z"/></svg>
      </div>` : '';

  const padY = data.bg ? '8px' : '4px';
  const padX = data.bg ? '14px' : '4px';
  dom.style.cssText = `position:absolute;left:${dom.style.left};top:${dom.style.top};padding:${padY} ${padX};${bgStyle}border-radius:30px;display:flex;align-items:center;gap:8px;cursor:move;`;
  dom.innerHTML = `${iconHtml}<span class="igl-handle" style="font-family:'Space Mono',monospace;font-weight:700;color:#FCB827;white-space:nowrap;font-size:${data.size}px;">${escapeHtml(data.text)}</span>`;
  if (data.rotation) dom.style.transform = `rotate(${data.rotation}deg)`;
}

/* ──────────── SHAPES ──────────── */
function addShape(kind) {
  const id = uid();
  const dom = document.createElement('div');
  dom.className = 'el el-shape';
  dom.dataset.id = id;
  dom.style.left = '35%';
  dom.style.top = '40%';
  dom.style.width = '30%';
  dom.style.aspectRatio = (kind === 'line') ? '10/1' : '1/1';
  if (kind === 'arrow-r' || kind === 'arrow-l') dom.style.aspectRatio = '2/1';
  if (kind === 'arrow-u' || kind === 'arrow-d') dom.style.aspectRatio = '1/2';

  dom.innerHTML = buildShapeSvg(kind, '#FCB827', 0, 1, 'full');
  stage.appendChild(dom);
  const data = {
    id, type: 'shape', dom, kind,
    color: '#FCB827', stroke: 0, opacity: 1,
    fillMode: 'full', rotation: 0
  };
  elements.push(data);
  attachInteractions(data);
  selectElement(id);
  renderLayers();
}

function buildShapeSvg(kind, color, strokeW, opacity, fillMode) {
  const fill = fillMode === 'none' ? 'none' : color;
  const stroke = strokeW > 0 || fillMode === 'none' ? color : 'none';
  const sw = (strokeW > 0 || fillMode === 'none') ? Math.max(strokeW, 2) : 0;
  const style = `fill:${fill};stroke:${stroke};stroke-width:${sw};stroke-linejoin:round;stroke-linecap:round;opacity:${opacity};`;

  switch (kind) {
    case 'rect':
      return `<svg viewBox="0 0 100 100" preserveAspectRatio="none"><rect x="2" y="2" width="96" height="96" rx="6" style="${style}"/></svg>`;
    case 'circle':
      return `<svg viewBox="0 0 100 100" preserveAspectRatio="none"><circle cx="50" cy="50" r="48" style="${style}"/></svg>`;
    case 'triangle':
      return `<svg viewBox="0 0 100 100" preserveAspectRatio="none"><polygon points="50,5 95,90 5,90" style="${style}"/></svg>`;
    case 'star':
      return `<svg viewBox="0 0 100 100" preserveAspectRatio="none"><polygon points="50,5 61,38 96,38 68,58 78,92 50,72 22,92 32,58 4,38 39,38" style="${style}"/></svg>`;
    case 'arrow-r':
      return `<svg viewBox="0 0 100 50" preserveAspectRatio="none"><polygon points="0,18 70,18 70,5 100,25 70,45 70,32 0,32" style="${style}"/></svg>`;
    case 'arrow-l':
      return `<svg viewBox="0 0 100 50" preserveAspectRatio="none"><polygon points="100,18 30,18 30,5 0,25 30,45 30,32 100,32" style="${style}"/></svg>`;
    case 'arrow-u':
      return `<svg viewBox="0 0 50 100" preserveAspectRatio="none"><polygon points="18,100 18,30 5,30 25,0 45,30 32,30 32,100" style="${style}"/></svg>`;
    case 'arrow-d':
      return `<svg viewBox="0 0 50 100" preserveAspectRatio="none"><polygon points="18,0 18,70 5,70 25,100 45,70 32,70 32,0" style="${style}"/></svg>`;
    case 'line':
      return `<svg viewBox="0 0 100 10" preserveAspectRatio="none"><rect x="0" y="3" width="100" height="4" style="fill:${color};opacity:${opacity}"/></svg>`;
    case 'burst': {
      const pts = [];
      for (let i = 0; i < 24; i++) {
        const a = (i / 24) * Math.PI * 2;
        const r = i % 2 === 0 ? 48 : 24;
        pts.push(`${50 + Math.cos(a) * r},${50 + Math.sin(a) * r}`);
      }
      return `<svg viewBox="0 0 100 100" preserveAspectRatio="none"><polygon points="${pts.join(' ')}" style="${style}"/></svg>`;
    }
    case 'heart':
      return `<svg viewBox="0 0 100 100" preserveAspectRatio="none"><path d="M50,85 C20,60 10,38 25,25 C38,15 50,25 50,35 C50,25 62,15 75,25 C90,38 80,60 50,85 Z" style="${style}"/></svg>`;
    case 'check':
      return `<svg viewBox="0 0 100 100" preserveAspectRatio="none"><polyline points="10,55 40,82 90,20" style="fill:none;stroke:${color};stroke-width:14;stroke-linecap:round;stroke-linejoin:round;opacity:${opacity}"/></svg>`;
    default: return '';
  }
}

/* ──────────── DRAG / RESIZE / ROTATE ──────────── */
function attachInteractions(data) {
  const el = data.dom;
  el.addEventListener('pointerdown', (e) => onElementPointerDown(e, data));
}

function onElementPointerDown(e, data) {
  e.stopPropagation();
  selectElement(data.id);
  if (e.target.classList.contains('handle')) return;

  const r = getStageRect();
  const er = data.dom.getBoundingClientRect();
  const offX = e.clientX - er.left;
  const offY = e.clientY - er.top;

  const mm = (ev) => {
    const nxRaw = ev.clientX - r.left - offX;
    const nyRaw = ev.clientY - r.top - offY;
    const w = data.dom.offsetWidth;
    const h = data.dom.offsetHeight;

    // Limites: permitir que se salga parcialmente
    let nx = Math.max(-w / 2, Math.min(nxRaw, stageW() - w / 2));
    let ny = Math.max(-h / 2, Math.min(nyRaw, stageH() - h / 2));

    // ── SNAP & GUÍAS DE ALINEACIÓN ──
    const snapped = snapToGuides(data, nx, ny, w, h);
    nx = snapped.x;
    ny = snapped.y;

    data.dom.style.left = (nx / stageW() * 100) + '%';
    data.dom.style.top  = (ny / stageH() * 100) + '%';

    // Badge de coordenadas
    showDragBadge(ev.clientX, ev.clientY,
      Math.round((nx / stageW()) * 1080) + ' × ' + Math.round((ny / stageH()) * 1350));

    positionHandles();
  };
  const up = () => {
    window.removeEventListener('pointermove', mm);
    window.removeEventListener('pointerup', up);
    hideAllGuides();
    hideDragBadge();
  };
  window.addEventListener('pointermove', mm);
  window.addEventListener('pointerup', up);
}

/* ══════════════════════════════════════════
   SISTEMA DE SNAP & GUÍAS DE ALINEACIÓN
══════════════════════════════════════════ */
function snapToGuides(draggingData, x, y, w, h) {
  const sW = stageW();
  const sH = stageH();

  // Puntos de referencia del elemento arrastrado
  const elLeft = x;
  const elCenterX = x + w / 2;
  const elRight = x + w;
  const elTop = y;
  const elCenterY = y + h / 2;
  const elBottom = y + h;

  // Targets de alineación: bordes y centro del stage
  const vTargets = [
    { pos: 0, type: 'stage-left' },
    { pos: sW / 2, type: 'stage-center' },
    { pos: sW, type: 'stage-right' },
    { pos: sW / 3, type: 'third' },
    { pos: (2 * sW) / 3, type: 'third' },
  ];
  const hTargets = [
    { pos: 0, type: 'stage-top' },
    { pos: sH / 2, type: 'stage-center' },
    { pos: sH, type: 'stage-bottom' },
    { pos: sH / 3, type: 'third' },
    { pos: (2 * sH) / 3, type: 'third' },
  ];

  // También considerar otros elementos como targets
  elements.forEach(other => {
    if (other.id === draggingData.id) return;
    const r = other.dom.getBoundingClientRect();
    const sR = getStageRect();
    const ox = r.left - sR.left;
    const oy = r.top - sR.top;
    vTargets.push(
      { pos: ox, type: 'other-left', ref: other.id },
      { pos: ox + r.width / 2, type: 'other-center', ref: other.id },
      { pos: ox + r.width, type: 'other-right', ref: other.id }
    );
    hTargets.push(
      { pos: oy, type: 'other-top', ref: other.id },
      { pos: oy + r.height / 2, type: 'other-center', ref: other.id },
      { pos: oy + r.height, type: 'other-bottom', ref: other.id }
    );
  });

  // Buscar snap vertical (eje X)
  let snapX = null;
  let snapXGuide = null;
  const xCandidates = [
    { pt: elLeft, offset: 0, name: 'left' },
    { pt: elCenterX, offset: -w / 2, name: 'center' },
    { pt: elRight, offset: -w, name: 'right' }
  ];

  for (const cand of xCandidates) {
    for (const t of vTargets) {
      if (Math.abs(cand.pt - t.pos) < SNAP_THRESHOLD) {
        snapX = t.pos + cand.offset;
        snapXGuide = { pos: t.pos, type: t.type };
        break;
      }
    }
    if (snapX !== null) break;
  }

  // Buscar snap horizontal (eje Y)
  let snapY = null;
  let snapYGuide = null;
  const yCandidates = [
    { pt: elTop, offset: 0, name: 'top' },
    { pt: elCenterY, offset: -h / 2, name: 'center' },
    { pt: elBottom, offset: -h, name: 'bottom' }
  ];

  for (const cand of yCandidates) {
    for (const t of hTargets) {
      if (Math.abs(cand.pt - t.pos) < SNAP_THRESHOLD) {
        snapY = t.pos + cand.offset;
        snapYGuide = { pos: t.pos, type: t.type };
        break;
      }
    }
    if (snapY !== null) break;
  }

  // Aplicar snap y mostrar guías correspondientes
  const finalX = snapX !== null ? snapX : x;
  const finalY = snapY !== null ? snapY : y;

  // Mostrar/ocultar guías
  hideAllGuides();
  if (snapXGuide) showVerticalGuide(snapXGuide.pos, snapXGuide.type);
  if (snapYGuide) showHorizontalGuide(snapYGuide.pos, snapYGuide.type);

  return { x: finalX, y: finalY };
}

function showVerticalGuide(pos, type) {
  const leftPct = (pos / stageW()) * 100;
  let guide;
  if (type === 'stage-left' || type === 'stage-center' || type === 'stage-right' || type === 'third') {
    // usar una de las guías principales
    const id = type === 'stage-left' ? 'guide-v-left'
             : type === 'stage-right' ? 'guide-v-right'
             : 'guide-v-center';
    guide = $(id);
  } else {
    guide = $('guide-v-other');
  }
  guide.style.left = leftPct + '%';
  guide.classList.add('show');
}

function showHorizontalGuide(pos, type) {
  const topPct = (pos / stageH()) * 100;
  let guide;
  if (type === 'stage-top' || type === 'stage-center' || type === 'stage-bottom' || type === 'third') {
    const id = type === 'stage-top' ? 'guide-h-top'
             : type === 'stage-bottom' ? 'guide-h-bottom'
             : 'guide-h-center';
    guide = $(id);
  } else {
    guide = $('guide-h-other');
  }
  guide.style.top = topPct + '%';
  guide.classList.add('show');
}

function hideAllGuides() {
  ['guide-v-left','guide-v-center','guide-v-right',
   'guide-h-top','guide-h-center','guide-h-bottom',
   'guide-v-other','guide-h-other'].forEach(id => {
    const g = $(id);
    if (g) g.classList.remove('show');
  });
}

function showDragBadge(x, y, txt) {
  const b = $('dragBadge');
  b.textContent = txt;
  b.style.left = (x + 15) + 'px';
  b.style.top = (y + 15) + 'px';
  b.classList.add('show');
}
function hideDragBadge() {
  $('dragBadge').classList.remove('show');
}

function positionHandles() {
  removeHandles();
  if (!selectedId) return;
  const data = elements.find(e => e.id === selectedId);
  if (!data) return;
  const el = data.dom;

  const se = document.createElement('div');
  se.className = 'handle h-se';
  se.style.right = '-8px';
  se.style.bottom = '-8px';
  el.appendChild(se);
  se.addEventListener('pointerdown', (e) => onResizeStart(e, data));

  const rot = document.createElement('div');
  rot.className = 'handle h-rot';
  rot.style.left = '50%';
  rot.style.top = '-32px';
  rot.style.transform = 'translateX(-50%)';
  el.appendChild(rot);
  rot.addEventListener('pointerdown', (e) => onRotateStart(e, data));
}

function removeHandles() {
  document.querySelectorAll('.handle').forEach(h => h.remove());
}

function onResizeStart(e, data) {
  e.stopPropagation();
  const startX = e.clientX;
  const startY = e.clientY;
  const startW = data.dom.offsetWidth;
  const startH = data.dom.offsetHeight;
  const isText = data.type === 'text';
  const isEmoji = data.type === 'emoji';
  const isIgLabel = data.type === 'iglabel';
  const aspect = startW / startH;

  const mm = (ev) => {
    const dx = ev.clientX - startX;
    const dy = ev.clientY - startY;
    if (isText) {
      const newW = Math.max(40, startW + dx);
      data.dom.style.width = (newW / stageW() * 100) + '%';
      const factor = newW / startW;
      const newSize = Math.max(10, Math.round(data.size * factor));
      data.size = newSize;
      data.dom.style.fontSize = newSize + 'px';
      if ($('eTxtSize')) {
        $('eTxtSize').value = newSize;
        $('eTxtSizeVal').textContent = newSize + 'px';
      }
    } else if (isEmoji) {
      const delta = Math.max(dx, dy);
      const newSize = Math.max(20, data.size + delta);
      data.size = newSize;
      data.dom.style.fontSize = newSize + 'px';
      if ($('eEmojiSize')) {
        $('eEmojiSize').value = newSize;
        $('eEmojiSizeVal').textContent = newSize + 'px';
      }
    } else if (isIgLabel) {
      const delta = Math.max(dx, dy);
      const factor = 1 + delta / Math.max(startW, 1);
      const newSize = Math.max(10, Math.min(60, Math.round(data.size * factor)));
      data.size = newSize;
      renderIgLabel(data);
      if ($('eIgSize')) {
        $('eIgSize').value = newSize;
        $('eIgSizeVal').textContent = newSize + 'px';
      }
    } else {
      // shapes, logo, image — mantener proporciones
      const delta = Math.max(dx, dy);
      const newW = Math.max(20, startW + delta);
      const newH = newW / aspect;
      data.dom.style.width = (newW / stageW() * 100) + '%';
      data.dom.style.height = (newH / stageH() * 100) + '%';
    }
    positionHandles();
  };
  const up = () => {
    window.removeEventListener('pointermove', mm);
    window.removeEventListener('pointerup', up);
  };
  window.addEventListener('pointermove', mm);
  window.addEventListener('pointerup', up);
}

function onRotateStart(e, data) {
  e.stopPropagation();
  const er = data.dom.getBoundingClientRect();
  const cx = er.left + er.width / 2;
  const cy = er.top + er.height / 2;
  const startAngle = Math.atan2(e.clientY - cy, e.clientX - cx);
  const startRot = data.rotation || 0;

  const mm = (ev) => {
    const angle = Math.atan2(ev.clientY - cy, ev.clientX - cx);
    const diff = (angle - startAngle) * 180 / Math.PI;
    data.rotation = Math.round(startRot + diff);
    applyTransform(data);
    if ($('eRot')) {
      $('eRot').value = data.rotation;
      $('eRotVal').textContent = data.rotation + '°';
    }
  };
  const up = () => {
    window.removeEventListener('pointermove', mm);
    window.removeEventListener('pointerup', up);
  };
  window.addEventListener('pointermove', mm);
  window.addEventListener('pointerup', up);
}

function applyTransform(data) {
  data.dom.style.transform = `rotate(${data.rotation || 0}deg)`;
}

stage.addEventListener('pointerdown', (e) => {
  if (e.target === stage || e.target === bgLayer || e.target.closest('.bg-layer')) {
    selectElement(null);
  }
});

/* ──────────── SELECT & EDIT PANELS ──────────── */
function selectElement(id) {
  selectedId = id;
  elements.forEach(e => e.dom.classList.toggle('selected', e.id === id));
  removeHandles();

  ['emptyEditPanel','editTextPanel','editShapePanel','editLogoPanel','editImagePanel','editEmojiPanel','editIgLabelPanel','commonEditPanel']
    .forEach(p => $(p).style.display = 'none');

  if (!id) {
    $('emptyEditPanel').style.display = 'block';
    renderLayers();
    return;
  }

  const data = elements.find(e => e.id === id);
  if (!data) return;
  positionHandles();

  if (data.type === 'text') {
    $('editTextPanel').style.display = 'block';
    $('commonEditPanel').style.display = 'block';
    $('eTxtContent').value = data.content;
    $('eTxtFont').value = data.font;
    $('eTxtSize').value = data.size;
    $('eTxtSizeVal').textContent = data.size + 'px';
    $('eTxtWeight').value = data.weight;
    $('eTxtStroke').checked = !!data.stroke;
    $('eTxtBg').checked = !!data.bg;
    setTextAlignUI(data.align);
    renderColorPicker('eTxtColorRow', data.color, (c) => { data.color = c; updateSelectedText(); });
  } else if (data.type === 'shape') {
    $('editShapePanel').style.display = 'block';
    $('commonEditPanel').style.display = 'block';
    $('eShapeStroke').value = data.stroke;
    $('eShapeStrokeVal').textContent = data.stroke + 'px';
    $('eShapeOp').value = Math.round(data.opacity * 100);
    $('eShapeOpVal').textContent = Math.round(data.opacity * 100) + '%';
    $('fillFull').classList.toggle('sel', data.fillMode === 'full');
    $('fillNone').classList.toggle('sel', data.fillMode === 'none');
    renderColorPicker('eShapeColorRow', data.color, (c) => { data.color = c; updateSelectedShape(); });
  } else if (data.type === 'logo') {
    $('editLogoPanel').style.display = 'block';
    $('commonEditPanel').style.display = 'block';
    $('eLogoOp').value = Math.round((data.opacity || 1) * 100);
    $('eLogoOpVal').textContent = Math.round((data.opacity || 1) * 100) + '%';
  } else if (data.type === 'image') {
    $('editImagePanel').style.display = 'block';
    $('commonEditPanel').style.display = 'block';
    $('eImgOp').value = Math.round((data.opacity || 1) * 100);
    $('eImgOpVal').textContent = Math.round((data.opacity || 1) * 100) + '%';
    $('eImgRadius').value = data.radius || 0;
    $('eImgRadiusVal').textContent = (data.radius || 0) + 'px';
    ['contain','cover','fill'].forEach(f => {
      $('fit-' + f).classList.toggle('sel', data.fit === f);
    });
  } else if (data.type === 'emoji') {
    $('editEmojiPanel').style.display = 'block';
    $('commonEditPanel').style.display = 'block';
    $('eEmojiChar').value = data.char;
    $('eEmojiSize').value = data.size;
    $('eEmojiSizeVal').textContent = data.size + 'px';
  } else if (data.type === 'iglabel') {
    $('editIgLabelPanel').style.display = 'block';
    $('commonEditPanel').style.display = 'block';
    $('eIgText').value = data.text;
    $('eIgSize').value = data.size;
    $('eIgSizeVal').textContent = data.size + 'px';
    $('eIgShowIcon').checked = data.showIcon;
    $('eIgBg').checked = data.bg;
  }

  $('eRot').value = data.rotation || 0;
  $('eRotVal').textContent = (data.rotation || 0) + '°';
  renderLayers();
}

function renderColorPicker(containerId, current, onPick) {
  const ct = $(containerId);
  ct.innerHTML = '';
  KROTON_COLORS.forEach(c => {
    const d = document.createElement('div');
    d.className = 'color-dot' + (c === current ? ' sel' : '');
    d.style.background = c;
    if (c === '#ffffff' || c === '#000000') d.style.border = '2px solid #444';
    d.onclick = () => {
      onPick(c);
      ct.querySelectorAll('.color-dot').forEach(x => x.classList.remove('sel'));
      d.classList.add('sel');
    };
    ct.appendChild(d);
  });
}

/* ──────────── UPDATE HANDLERS ──────────── */
function updateSelectedText() {
  const data = elements.find(e => e.id === selectedId);
  if (!data || data.type !== 'text') return;
  data.content = $('eTxtContent').value;
  data.font = $('eTxtFont').value;
  data.size = +$('eTxtSize').value;
  data.weight = $('eTxtWeight').value;
  data.stroke = $('eTxtStroke').checked;
  data.bg = $('eTxtBg').checked;
  $('eTxtSizeVal').textContent = data.size + 'px';

  const dom = data.dom;
  dom.textContent = data.content;
  dom.style.fontFamily = data.font;
  dom.style.fontSize = data.size + 'px';
  dom.style.fontWeight = data.weight;
  dom.style.color = data.color;
  dom.style.textAlign = data.align;
  dom.style.textShadow = data.stroke
    ? '-2px -2px 0 #000, 2px -2px 0 #000, -2px 2px 0 #000, 2px 2px 0 #000, 0 0 4px #000'
    : 'none';

  if (data.bg) {
    dom.style.background = '#FCB827';
    dom.style.padding = '10px 20px';
    dom.style.borderRadius = '10px';
    dom.style.display = 'inline-block';
  } else {
    dom.style.background = 'transparent';
    dom.style.padding = '4px 6px';
    dom.style.borderRadius = '0';
    dom.style.display = 'block';
  }
  renderLayers();
}

function setTextAlign(align) {
  const data = elements.find(e => e.id === selectedId);
  if (!data || data.type !== 'text') return;
  data.align = align;
  data.dom.style.textAlign = align;
  setTextAlignUI(align);
}
function setTextAlignUI(align) {
  ['l', 'c', 'r'].forEach(k => $('al-' + k).classList.remove('sel'));
  const map = { left: 'l', center: 'c', right: 'r' };
  $('al-' + map[align]).classList.add('sel');
}

function updateSelectedShape() {
  const data = elements.find(e => e.id === selectedId);
  if (!data || data.type !== 'shape') return;
  data.stroke = +$('eShapeStroke').value;
  data.opacity = +$('eShapeOp').value / 100;
  $('eShapeStrokeVal').textContent = data.stroke + 'px';
  $('eShapeOpVal').textContent = Math.round(data.opacity * 100) + '%';
  data.dom.innerHTML = buildShapeSvg(data.kind, data.color, data.stroke, data.opacity, data.fillMode);
}

function setShapeFill(mode) {
  const data = elements.find(e => e.id === selectedId);
  if (!data || data.type !== 'shape') return;
  data.fillMode = mode;
  $('fillFull').classList.toggle('sel', mode === 'full');
  $('fillNone').classList.toggle('sel', mode === 'none');
  updateSelectedShape();
}

function updateSelectedLogo() {
  const data = elements.find(e => e.id === selectedId);
  if (!data || data.type !== 'logo') return;
  data.opacity = +$('eLogoOp').value / 100;
  $('eLogoOpVal').textContent = Math.round(data.opacity * 100) + '%';
  data.dom.style.opacity = data.opacity;
}

function updateSelectedImage() {
  const data = elements.find(e => e.id === selectedId);
  if (!data || data.type !== 'image') return;
  data.opacity = +$('eImgOp').value / 100;
  data.radius = +$('eImgRadius').value;
  $('eImgOpVal').textContent = Math.round(data.opacity * 100) + '%';
  $('eImgRadiusVal').textContent = data.radius + 'px';
  data.dom.style.opacity = data.opacity;
  data.dom.style.borderRadius = data.radius + 'px';
}

function setImageFit(fit) {
  const data = elements.find(e => e.id === selectedId);
  if (!data || data.type !== 'image') return;
  data.fit = fit;
  data.dom.classList.remove('fit-contain','fit-cover','fit-fill');
  data.dom.classList.add('fit-' + fit);
  ['contain','cover','fill'].forEach(f => {
    $('fit-' + f).classList.toggle('sel', fit === f);
  });
}

function updateSelectedEmoji() {
  const data = elements.find(e => e.id === selectedId);
  if (!data || data.type !== 'emoji') return;
  data.char = $('eEmojiChar').value || data.char;
  data.size = +$('eEmojiSize').value;
  $('eEmojiSizeVal').textContent = data.size + 'px';
  data.dom.textContent = data.char;
  data.dom.style.fontSize = data.size + 'px';
  renderLayers();
}

function updateSelectedIgLabel() {
  const data = elements.find(e => e.id === selectedId);
  if (!data || data.type !== 'iglabel') return;
  data.text = $('eIgText').value;
  data.size = +$('eIgSize').value;
  data.showIcon = $('eIgShowIcon').checked;
  data.bg = $('eIgBg').checked;
  $('eIgSizeVal').textContent = data.size + 'px';
  renderIgLabel(data);
  positionHandles();
  renderLayers();
}

function updateSelectedRotation() {
  const data = elements.find(e => e.id === selectedId);
  if (!data) return;
  data.rotation = +$('eRot').value;
  $('eRotVal').textContent = data.rotation + '°';
  applyTransform(data);
  positionHandles();
}

function centerSelectedH() {
  const data = elements.find(e => e.id === selectedId);
  if (!data) return;
  const w = data.dom.offsetWidth;
  const newLeftPx = (stageW() - w) / 2;
  data.dom.style.left = (newLeftPx / stageW() * 100) + '%';
  positionHandles();
}
function centerSelectedV() {
  const data = elements.find(e => e.id === selectedId);
  if (!data) return;
  const h = data.dom.offsetHeight;
  const newTopPx = (stageH() - h) / 2;
  data.dom.style.top = (newTopPx / stageH() * 100) + '%';
  positionHandles();
}

/* ──────────── ACTIONS ──────────── */
function duplicateSelected() {
  const data = elements.find(e => e.id === selectedId);
  if (!data) return;
  if (data.type === 'text') {
    addText(data.content, null);
    const neu = elements[elements.length - 1];
    Object.assign(neu, {
      content: data.content, font: data.font, size: data.size,
      weight: data.weight, color: data.color, align: data.align,
      stroke: data.stroke, bg: data.bg, rotation: data.rotation
    });
    selectElement(neu.id);
    $('eTxtContent').value = neu.content;
    updateSelectedText();
    applyTransform(neu);
  } else if (data.type === 'shape') {
    addShape(data.kind);
    const neu = elements[elements.length - 1];
    Object.assign(neu, {
      color: data.color, stroke: data.stroke,
      opacity: data.opacity, fillMode: data.fillMode, rotation: data.rotation
    });
    neu.dom.innerHTML = buildShapeSvg(neu.kind, neu.color, neu.stroke, neu.opacity, neu.fillMode);
    applyTransform(neu);
  } else if (data.type === 'logo') {
    addLogo();
  } else if (data.type === 'image') {
    addImageElement(data.dataUrl);
    const neu = elements[elements.length - 1];
    Object.assign(neu, {
      fit: data.fit, opacity: data.opacity, radius: data.radius, rotation: data.rotation
    });
    neu.dom.classList.remove('fit-contain','fit-cover','fit-fill');
    neu.dom.classList.add('fit-' + neu.fit);
    neu.dom.style.opacity = neu.opacity;
    neu.dom.style.borderRadius = neu.radius + 'px';
    applyTransform(neu);
  } else if (data.type === 'emoji') {
    addEmoji(data.char);
    const neu = elements[elements.length - 1];
    neu.size = data.size;
    neu.dom.style.fontSize = neu.size + 'px';
  } else if (data.type === 'iglabel') {
    addInstagramLabel(data.text, !data.showIcon);
  }
}

function deleteSelected() {
  if (selectedId) removeElement(selectedId);
}

function removeElement(id) {
  const idx = elements.findIndex(e => e.id === id);
  if (idx < 0) return;
  const data = elements[idx];
  data.dom.remove();
  elements.splice(idx, 1);
  if (data.type === 'logo') $('logoToggle').checked = false;
  if (selectedId === id) selectElement(null);
  renderLayers();
}

function bringToFront() {
  const data = elements.find(e => e.id === selectedId);
  if (!data) return;
  stage.appendChild(data.dom);
  positionHandles();
}
function sendToBack() {
  const data = elements.find(e => e.id === selectedId);
  if (!data) return;
  stage.insertBefore(data.dom, bgLayer.nextSibling);
  positionHandles();
}

/* ──────────── LAYERS ──────────── */
function renderLayers() {
  const list = $('layersList');
  if (!elements.length) {
    list.innerHTML = '<div class="empty-hint">Sin elementos aún</div>';
    return;
  }
  list.innerHTML = [...elements].reverse().map(e => {
    let icon, name;
    if (e.type === 'text') { icon = '📝'; name = (e.content || '').substring(0, 22) || 'Texto'; }
    else if (e.type === 'logo') { icon = '🖼️'; name = 'Logo Kroton'; }
    else if (e.type === 'image') { icon = '🖼️'; name = 'Imagen'; }
    else if (e.type === 'emoji') { icon = e.char; name = 'Emoji ' + e.char; }
    else if (e.type === 'iglabel') { icon = '📸'; name = e.text || 'Instagram'; }
    else { icon = '🔷'; name = 'Forma: ' + (e.kind || ''); }
    return `<div class="layer-item ${e.id === selectedId ? 'sel' : ''}" onclick="selectElement('${e.id}')">
      <span class="layer-icon">${icon}</span>
      <span class="layer-name">${escapeHtml(name)}</span>
      <button class="layer-del" onclick="event.stopPropagation();removeElement('${e.id}')">✕</button>
    </div>`;
  }).join('');
}

function escapeHtml(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

/* ══════════════════════════════════════════════════════════════
   EXPORT — 1080×1350 — DIBUJO NATIVO EN CANVAS
══════════════════════════════════════════════════════════════ */
async function downloadImage() {
  const btn = document.querySelector('.btn-download');
  btn.disabled = true;
  btn.textContent = '⏳ GENERANDO...';

  try {
    const cvs = document.createElement('canvas');
    cvs.width = OUTPUT_W;
    cvs.height = OUTPUT_H;
    const ctx = cvs.getContext('2d');

    const scaleX = OUTPUT_W / stageW();
    const scaleY = OUTPUT_H / stageH();

    /* 1) Fondo */
    drawTemplateBG(ctx, currentTemplate, OUTPUT_W, OUTPUT_H);

    /* 2) Asegurar logo cargado */
    if (!LOGO_READY) {
      await new Promise((resolve) => {
        if (LOGO_READY) return resolve();
        LOGO_IMAGE.onload = () => { LOGO_READY = true; resolve(); };
        LOGO_IMAGE.onerror = () => resolve();
      });
    }

    /* 3) Limpiar selección visual */
    const wasSelected = selectedId;
    removeHandles();
    document.querySelectorAll('.el').forEach(e => e.classList.remove('selected'));

    /* 4) Iterar elementos en orden de DOM */
    const children = [...stage.children].filter(c => c.classList.contains('el'));
    for (const ch of children) {
      const id = ch.dataset.id;
      const data = elements.find(x => x.id === id);
      if (!data) continue;

      const r = ch.getBoundingClientRect();
      const stageR = getStageRect();
      const x = (r.left - stageR.left) * scaleX;
      const y = (r.top - stageR.top) * scaleY;
      const w = r.width * scaleX;
      const h = r.height * scaleY;

      ctx.save();
      const cx = x + w / 2;
      const cy = y + h / 2;
      const rot = (data.rotation || 0) * Math.PI / 180;
      ctx.translate(cx, cy);
      ctx.rotate(rot);
      ctx.translate(-cx, -cy);

      if (data.type === 'text') {
        drawTextElement(ctx, data, x, y, w, h, scaleX);
      } else if (data.type === 'shape') {
        drawShapeNative(ctx, data, x, y, w, h);
      } else if (data.type === 'logo') {
        ctx.globalAlpha = data.opacity || 1;
        if (LOGO_IMAGE.complete && LOGO_IMAGE.naturalWidth > 0) {
          ctx.drawImage(LOGO_IMAGE, x, y, w, h);
        }
        ctx.globalAlpha = 1;
      } else if (data.type === 'image') {
        await drawUserImage(ctx, data, x, y, w, h);
      } else if (data.type === 'emoji') {
        drawEmojiElement(ctx, data, x, y, w, h, scaleX);
      } else if (data.type === 'iglabel') {
        drawIgLabelElement(ctx, data, x, y, w, h, scaleX);
      }

      ctx.restore();
    }

    /* 5) Restaurar selección */
    if (wasSelected) {
      const selData = elements.find(e => e.id === wasSelected);
      if (selData) {
        selData.dom.classList.add('selected');
        positionHandles();
      }
    }

    /* 6) Descargar */
    cvs.toBlob((blob) => {
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `kroton-feed-${Date.now()}.png`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      setTimeout(() => URL.revokeObjectURL(url), 3000);
      showToast('✅ ¡Imagen descargada! 1080×1350');
      btn.disabled = false;
      btn.textContent = '⬇ DESCARGAR 1080×1350';
    }, 'image/png', 1.0);
  } catch (err) {
    console.error(err);
    btn.disabled = false;
    btn.textContent = '⬇ DESCARGAR 1080×1350';
    alert('Error al descargar: ' + err.message);
  }
}

/* ──────────── BACKGROUND DRAWING EN CANVAS ──────────── */
function drawTemplateBG(ctx, id, W, H) {
  ctx.fillStyle = '#000';
  ctx.fillRect(0, 0, W, H);

  const radGrad = (x, y, r1, r2, stops) => {
    const g = ctx.createRadialGradient(x, y, r1, x, y, r2);
    stops.forEach(s => g.addColorStop(s[0], s[1]));
    return g;
  };
  const linGrad = (x1, y1, x2, y2, stops) => {
    const g = ctx.createLinearGradient(x1, y1, x2, y2);
    stops.forEach(s => g.addColorStop(s[0], s[1]));
    return g;
  };

  switch (id) {
    case 'fire':
      ctx.fillStyle = radGrad(W*0.7, H*0.2, 0, W*0.7, [[0,'rgba(252,184,39,0.35)'],[1,'rgba(0,0,0,0)']]);
      ctx.fillRect(0,0,W,H);
      ctx.fillStyle = radGrad(W*0.2, H*0.85, 0, W*0.6, [[0,'rgba(252,184,39,0.18)'],[1,'rgba(0,0,0,0)']]);
      ctx.fillRect(0,0,W,H);
      break;
    case 'dark-frame':
      ctx.strokeStyle = '#FCB827';
      ctx.lineWidth = W * 0.008;
      ctx.strokeRect(W*0.04, H*0.04, W*0.92, H*0.92);
      ctx.strokeStyle = 'rgba(252,184,39,0.3)';
      ctx.lineWidth = W * 0.003;
      ctx.strokeRect(W*0.065, H*0.065, W*0.87, H*0.87);
      break;
    case 'gradient-v':
      ctx.fillStyle = linGrad(0,0,0,H, [[0,'#000'],[0.6,'#1a1100'],[1,'#FCB827']]);
      ctx.fillRect(0,0,W,H);
      break;
    case 'gradient-d':
      ctx.fillStyle = linGrad(0,0,W,H, [[0,'#000'],[0.45,'#0d0800'],[1,'#d99a1a']]);
      ctx.fillRect(0,0,W,H);
      break;
    case 'yellow-solid':
      ctx.fillStyle = '#FCB827';
      ctx.fillRect(0,0,W,H);
      ctx.fillStyle = radGrad(W*0.25, H*0.2, 0, W*0.7, [[0,'rgba(255,255,255,0.35)'],[1,'rgba(0,0,0,0)']]);
      ctx.fillRect(0,0,W,H);
      ctx.fillStyle = radGrad(W*0.8, H*0.9, 0, W*0.6, [[0,'rgba(0,0,0,0.2)'],[1,'rgba(0,0,0,0)']]);
      ctx.fillRect(0,0,W,H);
      break;
    case 'dots': {
      const step = 24 * (W / 540);
      ctx.fillStyle = 'rgba(252,184,39,0.18)';
      for (let y = 0; y < H; y += step) {
        for (let x = 0; x < W; x += step) {
          ctx.beginPath();
          ctx.arc(x, y, 2 * (W/540), 0, Math.PI * 2);
          ctx.fill();
        }
      }
      ctx.fillStyle = radGrad(W/2, H/2, 0, W*0.6, [[0,'rgba(252,184,39,0.1)'],[1,'rgba(0,0,0,0)']]);
      ctx.fillRect(0,0,W,H);
      break;
    }
    case 'grid': {
      const step = 40 * (W/540);
      ctx.strokeStyle = 'rgba(252,184,39,0.1)';
      ctx.lineWidth = 1.5 * (W/540);
      for (let x = 0; x <= W; x += step) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke();
      }
      for (let y = 0; y <= H; y += step) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke();
      }
      break;
    }
    case 'stripes': {
      const step = 30 * (W/540);
      ctx.save();
      ctx.strokeStyle = 'rgba(252,184,39,0.09)';
      ctx.lineWidth = 2 * (W/540);
      for (let i = -H; i < W + H; i += step) {
        ctx.beginPath();
        ctx.moveTo(i, 0);
        ctx.lineTo(i + H, H);
        ctx.stroke();
      }
      ctx.restore();
      break;
    }
    case 'spot':
      ctx.fillStyle = radGrad(W/2, H/2, 0, W*0.4, [[0,'#FCB827'],[0.4,'rgba(252,184,39,0.3)'],[1,'rgba(0,0,0,0)']]);
      ctx.fillRect(0,0,W,H);
      break;
    case 'half':
      ctx.fillStyle = linGrad(W*0.45, 0, W, H, [[0,'#FCB827'],[1,'#d99a1a']]);
      ctx.fillRect(W*0.45, 0, W*0.55, H);
      break;
    case 'burst': {
      const cx = W/2, cy = H/2;
      const maxR = Math.max(W, H);
      for (let i = 0; i < 24; i++) {
        const a1 = (i / 24) * Math.PI * 2;
        const a2 = ((i + 1) / 24) * Math.PI * 2;
        ctx.beginPath();
        ctx.moveTo(cx, cy);
        ctx.arc(cx, cy, maxR, a1, a2);
        ctx.closePath();
        ctx.fillStyle = i % 2 === 0 ? 'rgba(252,184,39,0.35)' : 'rgba(252,184,39,0.1)';
        ctx.fill();
      }
      ctx.fillStyle = radGrad(cx, cy, 0, W*0.35, [[0,'rgba(0,0,0,0.7)'],[1,'rgba(0,0,0,0)']]);
      ctx.fillRect(0,0,W,H);
      break;
    }
    case 'clean':
      ctx.fillStyle = linGrad(0, H*0.96, W, H, [[0,'#FCB827'],[1,'#ffd770']]);
      ctx.fillRect(0, H*0.96, W, H*0.04);
      ctx.fillStyle = linGrad(0, 0, W, 0, [[0,'rgba(0,0,0,0)'],[0.5,'#FCB827'],[1,'rgba(0,0,0,0)']]);
      ctx.fillRect(0, 0, W, 3);
      break;
  }
}

/* ──────────── TEXT ──────────── */
function drawTextElement(ctx, data, x, y, w, h, scaleFactor) {
  const fontSize = data.size * scaleFactor;
  const weight = data.weight || '700';
  ctx.font = `${weight} ${fontSize}px ${data.font}`;
  ctx.textBaseline = 'top';

  const lines = wrapText(ctx, data.content, w - 12 * scaleFactor);
  const lineHeight = fontSize * 1.1;

  if (data.bg) {
    const padX = 20 * scaleFactor;
    const padY = 10 * scaleFactor;
    ctx.fillStyle = '#FCB827';
    const textH = lines.length * lineHeight;
    const maxLineW = Math.max(...lines.map(l => ctx.measureText(l).width));
    const bgW = maxLineW + padX * 2;
    const bgH = textH + padY * 2;
    let bgX;
    if (data.align === 'left') bgX = x;
    else if (data.align === 'right') bgX = x + w - bgW;
    else bgX = x + (w - bgW) / 2;
    const radius = 10 * scaleFactor;
    roundRect(ctx, bgX, y, bgW, bgH, radius);
    ctx.fill();
  }

  const offsetY = data.bg ? 10 * scaleFactor : 4 * scaleFactor;
  let cy = y + offsetY;

  lines.forEach(line => {
    let tx;
    if (data.align === 'left') {
      ctx.textAlign = 'left';
      tx = x + (data.bg ? 20 * scaleFactor : 6 * scaleFactor);
    } else if (data.align === 'right') {
      ctx.textAlign = 'right';
      tx = x + w - (data.bg ? 20 * scaleFactor : 6 * scaleFactor);
    } else {
      ctx.textAlign = 'center';
      tx = x + w / 2;
    }

    if (data.stroke) {
      ctx.strokeStyle = '#000';
      ctx.lineWidth = Math.max(4, fontSize * 0.08);
      ctx.lineJoin = 'round';
      ctx.strokeText(line, tx, cy);
    }
    ctx.fillStyle = data.color;
    ctx.fillText(line, tx, cy);
    cy += lineHeight;
  });
}

function wrapText(ctx, text, maxW) {
  const out = [];
  const paragraphs = (text || '').split('\n');
  paragraphs.forEach(para => {
    const words = para.split(' ');
    let line = '';
    words.forEach(word => {
      const test = line ? line + ' ' + word : word;
      if (ctx.measureText(test).width > maxW && line) {
        out.push(line);
        line = word;
      } else {
        line = test;
      }
    });
    if (line) out.push(line);
    if (!line && !words.length) out.push('');
  });
  return out;
}

function roundRect(ctx, x, y, w, h, r) {
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.lineTo(x + w - r, y);
  ctx.quadraticCurveTo(x + w, y, x + w, y + r);
  ctx.lineTo(x + w, y + h - r);
  ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
  ctx.lineTo(x + r, y + h);
  ctx.quadraticCurveTo(x, y + h, x, y + h - r);
  ctx.lineTo(x, y + r);
  ctx.quadraticCurveTo(x, y, x + r, y);
  ctx.closePath();
}

/* Cache de imágenes cargadas para export */
const imageCache = {};

function loadImageAsync(src) {
  return new Promise((resolve) => {
    if (imageCache[src] && imageCache[src].complete) {
      resolve(imageCache[src]);
      return;
    }
    const img = new Image();
    img.onload = () => { imageCache[src] = img; resolve(img); };
    img.onerror = () => resolve(null);
    img.src = src;
  });
}

async function drawUserImage(ctx, data, x, y, w, h) {
  const img = await loadImageAsync(data.dataUrl);
  if (!img) return;

  ctx.save();
  ctx.globalAlpha = data.opacity || 1;

  // Clip por border-radius si aplica
  const scaleF = Math.min(w, h) / stageW();
  const radiusPx = (data.radius || 0) * (1080 / stageW());
  if (radiusPx > 0) {
    roundRect(ctx, x, y, w, h, Math.min(radiusPx, Math.min(w, h) / 2));
    ctx.clip();
  }

  const fit = data.fit || 'contain';
  if (fit === 'fill') {
    // estirar
    ctx.drawImage(img, x, y, w, h);
  } else if (fit === 'cover') {
    // rellenar cortando
    const imgAR = img.naturalWidth / img.naturalHeight;
    const boxAR = w / h;
    let sx = 0, sy = 0, sw = img.naturalWidth, sh = img.naturalHeight;
    if (imgAR > boxAR) {
      // imagen más ancha: recortar lados
      sw = img.naturalHeight * boxAR;
      sx = (img.naturalWidth - sw) / 2;
    } else {
      // imagen más alta: recortar arriba/abajo
      sh = img.naturalWidth / boxAR;
      sy = (img.naturalHeight - sh) / 2;
    }
    ctx.drawImage(img, sx, sy, sw, sh, x, y, w, h);
  } else {
    // contain (default): respetar proporción, letterbox
    const imgAR = img.naturalWidth / img.naturalHeight;
    const boxAR = w / h;
    let dw, dh, dx, dy;
    if (imgAR > boxAR) {
      dw = w;
      dh = w / imgAR;
      dx = x;
      dy = y + (h - dh) / 2;
    } else {
      dh = h;
      dw = h * imgAR;
      dy = y;
      dx = x + (w - dw) / 2;
    }
    ctx.drawImage(img, dx, dy, dw, dh);
  }

  ctx.restore();
}

/* ──────────── EMOJI ──────────── */
function drawEmojiElement(ctx, data, x, y, w, h, scaleFactor) {
  const fontSize = data.size * scaleFactor;
  // usar emoji font del sistema
  ctx.font = `${fontSize}px "Apple Color Emoji","Segoe UI Emoji","Noto Color Emoji",sans-serif`;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillStyle = '#000';
  const cx = x + w / 2;
  const cy = y + h / 2;
  ctx.fillText(data.char, cx, cy);
}

/* ──────────── IG LABEL ──────────── */
function drawIgLabelElement(ctx, data, x, y, w, h, scaleFactor) {
  const fontSize = data.size * scaleFactor;
  const padX = 14 * scaleFactor;
  const padY = 8 * scaleFactor;
  const iconSize = fontSize * 1.5;
  const gap = 8 * scaleFactor;

  ctx.font = `700 ${fontSize}px 'Space Mono', monospace`;
  const textW = ctx.measureText(data.text).width;

  const contentW = (data.showIcon ? iconSize + gap : 0) + textW;
  const totalW = contentW + padX * 2;
  const totalH = Math.max(iconSize, fontSize) + padY * 2;
  const boxX = x + (w - totalW) / 2;
  const boxY = y + (h - totalH) / 2;

  if (data.bg) {
    roundRect(ctx, boxX, boxY, totalW, totalH, totalH / 2);
    ctx.fillStyle = 'rgba(0,0,0,0.75)';
    ctx.fill();
  }

  let drawX = boxX + padX;
  if (data.showIcon) {
    // icono Instagram: cuadro amarillo redondeado + cámara en negro
    const iconY = boxY + (totalH - iconSize) / 2;
    roundRect(ctx, drawX, iconY, iconSize, iconSize, iconSize * 0.25);
    const g = ctx.createLinearGradient(drawX, iconY, drawX + iconSize, iconY + iconSize);
    g.addColorStop(0, '#FCB827');
    g.addColorStop(1, '#ffd770');
    ctx.fillStyle = g;
    ctx.fill();

    // dibujar símbolo cámara simplificado
    const cx0 = drawX + iconSize / 2;
    const cy0 = iconY + iconSize / 2;
    const camR = iconSize * 0.28;
    // círculo exterior
    ctx.strokeStyle = '#000';
    ctx.lineWidth = iconSize * 0.08;
    ctx.beginPath();
    ctx.arc(cx0, cy0, camR, 0, Math.PI * 2);
    ctx.stroke();
    // punto superior derecho
    ctx.beginPath();
    ctx.arc(cx0 + iconSize * 0.25, cy0 - iconSize * 0.25, iconSize * 0.05, 0, Math.PI * 2);
    ctx.fillStyle = '#000';
    ctx.fill();

    drawX += iconSize + gap;
  }

  // texto amarillo
  ctx.textAlign = 'left';
  ctx.textBaseline = 'middle';
  ctx.fillStyle = '#FCB827';
  ctx.font = `700 ${fontSize}px 'Space Mono', monospace`;
  ctx.fillText(data.text, drawX, boxY + totalH / 2);
}

/* ──────────── SHAPES ──────────── */
function drawShapeNative(ctx, data, x, y, w, h) {
  const col = data.color;
  const op = data.opacity || 1;
  const sw = data.stroke || 0;
  const fill = data.fillMode !== 'none';
  const stroke = sw > 0 || !fill;
  const actualSw = stroke ? Math.max(sw, 2) : 0;
  const scaleFactor = Math.min(w, h) / 100;

  ctx.save();
  ctx.globalAlpha = op;
  ctx.lineJoin = 'round';
  ctx.lineCap = 'round';
  ctx.strokeStyle = col;
  ctx.fillStyle = col;
  ctx.lineWidth = actualSw;

  const k = data.kind;
  switch (k) {
    case 'rect': {
      const r = 6 * scaleFactor;
      roundRect(ctx, x + 2 * scaleFactor, y + 2 * scaleFactor, w - 4 * scaleFactor, h - 4 * scaleFactor, r);
      if (fill) ctx.fill();
      if (stroke) ctx.stroke();
      break;
    }
    case 'circle': {
      ctx.beginPath();
      ctx.ellipse(x + w/2, y + h/2, w/2 - 2, h/2 - 2, 0, 0, Math.PI * 2);
      if (fill) ctx.fill();
      if (stroke) ctx.stroke();
      break;
    }
    case 'triangle': {
      ctx.beginPath();
      ctx.moveTo(x + w/2, y + h * 0.05);
      ctx.lineTo(x + w * 0.95, y + h * 0.9);
      ctx.lineTo(x + w * 0.05, y + h * 0.9);
      ctx.closePath();
      if (fill) ctx.fill();
      if (stroke) ctx.stroke();
      break;
    }
    case 'star': {
      const pts = [[50,5],[61,38],[96,38],[68,58],[78,92],[50,72],[22,92],[32,58],[4,38],[39,38]];
      ctx.beginPath();
      pts.forEach((p, i) => {
        const px = x + (p[0]/100) * w;
        const py = y + (p[1]/100) * h;
        if (i === 0) ctx.moveTo(px, py); else ctx.lineTo(px, py);
      });
      ctx.closePath();
      if (fill) ctx.fill();
      if (stroke) ctx.stroke();
      break;
    }
    case 'arrow-r': {
      const pts = [[0,36],[70,36],[70,10],[100,50],[70,90],[70,64],[0,64]];
      drawPoly(ctx, pts, x, y, w, h, fill, stroke);
      break;
    }
    case 'arrow-l': {
      const pts = [[100,36],[30,36],[30,10],[0,50],[30,90],[30,64],[100,64]];
      drawPoly(ctx, pts, x, y, w, h, fill, stroke);
      break;
    }
    case 'arrow-u': {
      const pts = [[36,100],[36,30],[10,30],[50,0],[90,30],[64,30],[64,100]];
      drawPoly(ctx, pts, x, y, w, h, fill, stroke);
      break;
    }
    case 'arrow-d': {
      const pts = [[36,0],[36,70],[10,70],[50,100],[90,70],[64,70],[64,0]];
      drawPoly(ctx, pts, x, y, w, h, fill, stroke);
      break;
    }
    case 'line': {
      ctx.fillStyle = col;
      ctx.fillRect(x, y + h * 0.3, w, h * 0.4);
      break;
    }
    case 'burst': {
      const cx = x + w/2, cy = y + h/2;
      const rMax = Math.min(w, h) / 2 * 0.96;
      const rMin = rMax * 0.5;
      ctx.beginPath();
      for (let i = 0; i < 24; i++) {
        const a = (i / 24) * Math.PI * 2;
        const r = i % 2 === 0 ? rMax : rMin;
        const px = cx + Math.cos(a) * r;
        const py = cy + Math.sin(a) * r;
        if (i === 0) ctx.moveTo(px, py); else ctx.lineTo(px, py);
      }
      ctx.closePath();
      if (fill) ctx.fill();
      if (stroke) ctx.stroke();
      break;
    }
    case 'heart': {
      ctx.beginPath();
      ctx.moveTo(x + w*0.5, y + h*0.85);
      ctx.bezierCurveTo(x + w*0.2, y + h*0.6, x + w*0.1, y + h*0.38, x + w*0.25, y + h*0.25);
      ctx.bezierCurveTo(x + w*0.38, y + h*0.15, x + w*0.5, y + h*0.25, x + w*0.5, y + h*0.35);
      ctx.bezierCurveTo(x + w*0.5, y + h*0.25, x + w*0.62, y + h*0.15, x + w*0.75, y + h*0.25);
      ctx.bezierCurveTo(x + w*0.9, y + h*0.38, x + w*0.8, y + h*0.6, x + w*0.5, y + h*0.85);
      ctx.closePath();
      if (fill) ctx.fill();
      if (stroke) ctx.stroke();
      break;
    }
    case 'check': {
      ctx.beginPath();
      ctx.lineWidth = 14 * scaleFactor;
      ctx.strokeStyle = col;
      ctx.moveTo(x + w*0.1, y + h*0.55);
      ctx.lineTo(x + w*0.4, y + h*0.82);
      ctx.lineTo(x + w*0.9, y + h*0.2);
      ctx.stroke();
      break;
    }
  }
  ctx.restore();
}

function drawPoly(ctx, pts, x, y, w, h, fill, stroke) {
  ctx.beginPath();
  pts.forEach((p, i) => {
    const px = x + (p[0]/100) * w;
    const py = y + (p[1]/100) * h;
    if (i === 0) ctx.moveTo(px, py); else ctx.lineTo(px, py);
  });
  ctx.closePath();
  if (fill) ctx.fill();
  if (stroke) ctx.stroke();
}

function showToast(msg) {
  const t = $('toast');
  t.textContent = msg;
  t.classList.add('show');
  setTimeout(() => t.classList.remove('show'), 2800);
}

/* ──────────── KEYBOARD ──────────── */
document.addEventListener('keydown', (e) => {
  const tag = (e.target.tagName || '').toLowerCase();
  if (tag === 'input' || tag === 'textarea' || tag === 'select') return;

  if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
    e.preventDefault();
    deleteSelected();
  }
  if ((e.ctrlKey || e.metaKey) && e.key === 'd') {
    e.preventDefault();
    if (selectedId) duplicateSelected();
  }
  if (e.key === 'Escape') selectElement(null);
});

